+
+    let mut runtime = LabRuntime::new(config);
+    let root = runtime.state.create_root_region(Budget::INFINITE);
+    runtime.state.set_region_limits(root, limits);
+
+    let mut children_created = 0u32;
+    let mut children_rejected = 0u32;
+
